// ═══════════════════════════════════════════════════
//  نود: Process & Evaluate Row
// ═══════════════════════════════════════════════════

const row = $input.first().json;

const employeeName  = row['Employee Name']      || '';
const date          = row['Date']               || '';
const attendanceHrs = parseFloat(row['Attendance Hours'] || 0);
const absenceHrs    = parseFloat(row['Absence Hours']    || 0);
const reason        = row['Reason for Absence'] || 'N/A';
const totalHrs      = attendanceHrs + absenceHrs;

let rawAtt = parseFloat(row['Attendance %'] || 0);
let rawAbs = parseFloat(row['Absence %']    || 0);
let attendancePct = rawAtt <= 1 ? Math.round(rawAtt * 100) : Math.round(rawAtt);
let absencePct    = rawAbs <= 1 ? Math.round(rawAbs * 100) : Math.round(rawAbs);

if (totalHrs > 0 && rawAtt === 0 && rawAbs === 0) {
  attendancePct = Math.round((attendanceHrs / totalHrs) * 100);
  absencePct    = Math.round((absenceHrs    / totalHrs) * 100);
}

let status      = 'Normal';
let statusColor = '#185FA5';
let statusBg    = '#E6F1FB';
let statusEmoji = '✅';

if (attendancePct > 90) {
  status      = 'Top Performer';
  statusColor = '#3B6D11';
  statusBg    = '#EAF3DE';
  statusEmoji = '🏆';
} else if (absencePct > 30) {
  status      = 'Warning';
  statusColor = '#993C1D';
  statusBg    = '#FAECE7';
  statusEmoji = '⚠️';
}

if (!employeeName || !date) {
  throw new Error('Row is missing Employee Name or Date — skipping.');
}

const initials = employeeName.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2);

const telegramMessage = [
  `━━━━━━━━━━━━━━━━━━━━━`,
  `${statusEmoji} *ATTENDANCE REPORT*`,
  `━━━━━━━━━━━━━━━━━━━━━`,
  ``,
  `👤  *${employeeName}*`,
  `📅  ${date}`,
  ``,
  `⏱️  Total Hours     \`${totalHrs}h\``,
  `✅  Attendance      \`${attendancePct}%  (${attendanceHrs}h)\``,
  `❌  Absence         \`${absencePct}%  (${absenceHrs}h)\``,
  `📌  Reason          \`${reason}\``,
  ``,
  `${statusEmoji}  Status: *${status}*`,
  ``,
  `━━━━━━━━━━━━━━━━━━━━━`,
  `_n8n Attendance System_`
].join('\n');

const attBarWidth = Math.min(attendancePct, 100);
const absBarWidth = Math.min(absencePct, 100);

const emailBody = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f4f6f9;padding:32px 16px}
.container{max-width:600px;margin:0 auto}
.header{background:linear-gradient(135deg,#1a1a2e 0%,#16213e 60%,#0f3460 100%);border-radius:16px 16px 0 0;padding:32px 28px;position:relative;overflow:hidden}
.badge{display:inline-block;background:rgba(255,255,255,0.12);border:1px solid rgba(255,255,255,0.2);border-radius:20px;padding:4px 14px;font-size:11px;color:rgba(255,255,255,0.8);margin-bottom:18px;letter-spacing:0.04em}
.avatar{width:52px;height:52px;border-radius:50%;background:rgba(255,255,255,0.15);border:2px solid rgba(255,255,255,0.25);display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:600;color:white;margin-bottom:12px}
.emp-name{font-size:22px;font-weight:600;color:white;margin-bottom:4px}
.emp-sub{font-size:13px;color:rgba(255,255,255,0.55)}
.body{background:white;padding:24px 28px;border-radius:0 0 16px 16px;border:1px solid #e8ecf0;border-top:none}
.stats{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:24px}
.stat{background:#f8f9fb;border-radius:10px;padding:14px;text-align:center}
.stat-val{font-size:22px;font-weight:600;margin-bottom:2px}
.stat-label{font-size:11px;color:#6b7280;letter-spacing:0.03em}
.green{color:#1D9E75}.red{color:#D85A30}.blue{color:#185FA5}
.section-label{font-size:11px;font-weight:600;color:#9ca3af;text-transform:uppercase;letter-spacing:0.06em;margin-bottom:12px}
.detail-row{display:flex;justify-content:space-between;align-items:center;padding:11px 0;border-bottom:1px solid #f3f4f6;font-size:14px}
.detail-row:last-child{border-bottom:none;padding-bottom:0}
.detail-label{color:#6b7280}
.detail-val{font-weight:500;color:#111827}
.status-pill{display:inline-block;padding:4px 14px;border-radius:20px;font-size:12px;font-weight:600}
.divider{height:1px;background:#f3f4f6;margin:20px 0}
.bar-label{display:flex;justify-content:space-between;font-size:13px;margin-bottom:5px}
.bar-track{background:#f3f4f6;border-radius:99px;height:8px;overflow:hidden;margin-bottom:12px}
.bar-fill{height:8px;border-radius:99px}
.footer{text-align:center;font-size:11px;color:#9ca3af;margin-top:20px;padding-top:16px;border-top:1px solid #f3f4f6}
</style></head>
<body>
<div class="container">
  <div class="header">
    <div class="badge">ATTENDANCE REPORT</div>
    <div class="avatar">${initials}</div>
    <div class="emp-name">${employeeName}</div>
    <div class="emp-sub">${date}</div>
  </div>
  <div class="body">
    <div class="stats">
      <div class="stat"><div class="stat-val green">${attendancePct}%</div><div class="stat-label">Attendance</div></div>
      <div class="stat"><div class="stat-val red">${absencePct}%</div><div class="stat-label">Absence</div></div>
      <div class="stat"><div class="stat-val blue">${totalHrs}h</div><div class="stat-label">Total Hours</div></div>
    </div>
    <div class="section-label">Details</div>
    <div class="detail-row"><span class="detail-label">Attendance Hours</span><span class="detail-val">${attendanceHrs}h</span></div>
    <div class="detail-row"><span class="detail-label">Absence Hours</span><span class="detail-val">${absenceHrs}h</span></div>
    <div class="detail-row"><span class="detail-label">Reason</span><span class="detail-val">${reason}</span></div>
    <div class="detail-row">
      <span class="detail-label">Status</span>
      <span class="status-pill" style="background:${statusBg};color:${statusColor}">${statusEmoji} ${status}</span>
    </div>
    <div class="divider"></div>
    <div class="section-label">Breakdown</div>
    <div class="bar-label"><span style="color:#6b7280">Attendance</span><span style="color:#1D9E75;font-weight:500">${attendancePct}%</span></div>
    <div class="bar-track"><div class="bar-fill" style="width:${attBarWidth}%;background:#1D9E75"></div></div>
    <div class="bar-label"><span style="color:#6b7280">Absence</span><span style="color:#D85A30;font-weight:500">${absencePct}%</span></div>
    <div class="bar-track"><div class="bar-fill" style="width:${absBarWidth}%;background:#D85A30"></div></div>
    <div class="footer">Generated automatically by n8n · Employee Attendance System</div>
  </div>
</div>
</body></html>`;

return [{
  json: {
    employeeName, date, attendanceHrs, absenceHrs, totalHrs,
    attendancePct, absencePct, reason, status, statusEmoji,
    telegramMessage, emailBody,
    emailSubject: `${statusEmoji} Attendance Report — ${employeeName} — ${date}`
  }
}];

// ═══════════════════════════════════════════════════
//  نود: Build Daily Summary
// ═══════════════════════════════════════════════════

const rows = $input.all();
if (!rows || rows.length === 0) return [{ json: { skip: true } }];

const employees = {};

for (const item of rows) {
  const r = item.json;
  const name = r['Employee Name'] || '';
  if (!name || name === 'Employee Name') continue;

  const attHrs = parseFloat(r['Attendance Hours'] || 0);
  const absHrs = parseFloat(r['Absence Hours']    || 0);
  const total  = attHrs + absHrs;

  if (!employees[name]) {
    employees[name] = { name, totalAtt: 0, totalAbs: 0, totalHrs: 0 };
  }

  employees[name].totalAtt  += attHrs;
  employees[name].totalAbs  += absHrs;
  employees[name].totalHrs  += total;
}

const list = Object.values(employees).filter(e => e.totalHrs > 0);

list.forEach(e => {
  e.attPct = Math.round((e.totalAtt / e.totalHrs) * 100);
  e.absPct = Math.round((e.totalAbs / e.totalHrs) * 100);
  e.status = e.attPct > 90 ? '🏆 Top Performer' : e.absPct > 30 ? '⚠️ Warning' : '✅ Normal';
});

const topPerformer  = list.reduce((a, b) => a.attPct >= b.attPct ? a : b);
const highestAbsent = list.reduce((a, b) => a.absPct >= b.absPct ? a : b);
const totalAttHrs   = list.reduce((s, e) => s + e.totalAtt, 0);
const totalAbsHrs   = list.reduce((s, e) => s + e.totalAbs, 0);
const today         = new Date().toLocaleDateString('en-GB');

const breakdown = list.map(e =>
  `  ${e.status.split(' ')[0]}  *${e.name}*\n     ✅ ${e.attPct}%  ❌ ${e.absPct}%  ⏱️ ${e.totalAtt}h`
).join('\n\n');

const telegramSummary = [
  `━━━━━━━━━━━━━━━━━━━━━`,
  `📅 *DAILY SUMMARY REPORT*`,
  `━━━━━━━━━━━━━━━━━━━━━`,
  `📆  ${today}`,
  ``,
  `🏆  Top Performer`,
  `     *${topPerformer.name}* — ${topPerformer.attPct}%`,
  ``,
  `⚠️  Highest Absence`,
  `     *${highestAbsent.name}* — ${highestAbsent.absPct}%`,
  ``,
  `⏱️  Total Attendance   \`${totalAttHrs}h\``,
  `🚫  Total Absence      \`${totalAbsHrs}h\``,
  ``,
  `━━━━━━━━━━━━━━━━━━━━━`,
  `*Employee Breakdown:*`,
  ``,
  breakdown,
  ``,
  `━━━━━━━━━━━━━━━━━━━━━`,
  `_n8n Attendance System_`
].join('\n');

const tableRows = list.map(e => {
  const bg    = e.attPct > 90 ? '#EAF3DE' : e.absPct > 30 ? '#FAECE7' : '#E6F1FB';
  const color = e.attPct > 90 ? '#3B6D11' : e.absPct > 30 ? '#993C1D' : '#185FA5';
  return `<tr>
    <td style="padding:12px 14px;font-weight:500;color:#111827">${e.name}</td>
    <td style="padding:12px 14px;color:#1D9E75;font-weight:500;text-align:center">${e.attPct}%</td>
    <td style="padding:12px 14px;color:#D85A30;font-weight:500;text-align:center">${e.absPct}%</td>
    <td style="padding:12px 14px;text-align:center">${e.totalAtt}h</td>
    <td style="padding:12px 14px;text-align:center">
      <span style="background:${bg};color:${color};padding:3px 10px;border-radius:20px;font-size:12px;font-weight:600">${e.status}</span>
    </td>
  </tr>`;
}).join('');

const emailSummary = `<!DOCTYPE html>
<html><head><meta charset="UTF-8">
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#f4f6f9;padding:32px 16px}
.container{max-width:640px;margin:0 auto}
.header{background:linear-gradient(135deg,#1a1a2e 0%,#16213e 60%,#0f3460 100%);border-radius:16px 16px 0 0;padding:32px 28px}
.badge{display:inline-block;background:rgba(255,255,255,0.12);border:1px solid rgba(255,255,255,0.2);border-radius:20px;padding:4px 14px;font-size:11px;color:rgba(255,255,255,0.8);margin-bottom:14px;letter-spacing:0.04em}
.title{font-size:22px;font-weight:600;color:white;margin-bottom:4px}
.sub{font-size:13px;color:rgba(255,255,255,0.55)}
.body{background:white;padding:28px;border-radius:0 0 16px 16px;border:1px solid #e8ecf0;border-top:none}
.highlights{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin-bottom:24px}
.hl{background:#f8f9fb;border-radius:10px;padding:14px}
.hl-label{font-size:11px;color:#9ca3af;margin-bottom:6px;text-transform:uppercase;letter-spacing:0.04em}
.hl-val{font-size:16px;font-weight:600;color:#111827}
.hl-sub{font-size:12px;color:#6b7280;margin-top:2px}
.section-label{font-size:11px;font-weight:600;color:#9ca3af;text-transform:uppercase;letter-spacing:0.06em;margin-bottom:14px}
table{width:100%;border-collapse:collapse}
th{background:#f8f9fb;padding:10px 14px;text-align:left;font-size:11px;font-weight:600;color:#9ca3af;text-transform:uppercase;letter-spacing:0.04em}
tr:nth-child(even){background:#fafafa}
.footer{text-align:center;font-size:11px;color:#9ca3af;margin-top:20px}
</style></head>
<body>
<div class="container">
  <div class="header">
    <div class="badge">DAILY SUMMARY REPORT</div>
    <div class="title">Attendance Summary</div>
    <div class="sub">${today}</div>
  </div>
  <div class="body">
    <div class="highlights">
      <div class="hl">
        <div class="hl-label">Top Performer</div>
        <div class="hl-val">🏆 ${topPerformer.name}</div>
        <div class="hl-sub">${topPerformer.attPct}% attendance</div>
      </div>
      <div class="hl">
        <div class="hl-label">Highest Absence</div>
        <div class="hl-val">⚠️ ${highestAbsent.name}</div>
        <div class="hl-sub">${highestAbsent.absPct}% absence</div>
      </div>
      <div class="hl">
        <div class="hl-label">Total Attendance</div>
        <div class="hl-val" style="color:#1D9E75">${totalAttHrs}h</div>
      </div>
      <div class="hl">
        <div class="hl-label">Total Absence</div>
        <div class="hl-val" style="color:#D85A30">${totalAbsHrs}h</div>
      </div>
    </div>
    <div class="section-label">Employee Breakdown</div>
    <table>
      <thead><tr>
        <th>Employee</th>
        <th style="text-align:center">Att %</th>
        <th style="text-align:center">Abs %</th>
        <th style="text-align:center">Hours</th>
        <th style="text-align:center">Status</th>
      </tr></thead>
      <tbody>${tableRows}</tbody>
    </table>
    <div class="footer">Generated automatically by n8n · Employee Attendance System</div>
  </div>
</div>
</body></html>`;

return [{
  json: {
    today,
    topPerformer: topPerformer.name,
    highestAbsent: highestAbsent.name,
    totalAttHrs,
    totalAbsHrs,
    telegramSummary,
    emailSummary,
    emailSubject: `📅 Daily Attendance Summary — ${today}`
  }
}];

// يكتب في شيت Logs مباشرة عبر API
const data = $input.first().json;

return [{
  json: {
    "Employee Name": data.employeeName,
    "Total Att. Hours": data.attendanceHrs,
    "Total Abs. Hours": data.absenceHrs,
    "Total Working Hours": data.totalHrs,
    "Avg Attendance %": data.attendancePct,
    "Avg Absence %": data.absencePct,
    "Status": data.status,
    "Logged At": new Date().toISOString()
  }
}];

const d = $input.first().json;

return [{
  json: {
    "Employee Name":       d.employeeName,
    "Total Att. Hours":    d.attendanceHrs,
    "Total Abs. Hours":    d.absenceHrs,
    "Total Working Hours": d.totalHrs,
    "Avg Attendance %":    d.attendancePct,
    "Avg Absence %":       d.absencePct,
    "Status":              d.status,
    "Logged At":           new Date().toISOString()
  }
}];
